def read_and_validate_xml(
    file_path: str,
    xsd_path: Optional[str] = None,
    max_file_size_mb: float = 10.0
) -> Dict[str, Any]:
    """
    Reads and validates an XML document uploaded by a user.

    Args:
        file_path: Path to the uploaded XML file.
        xsd_path: Optional path to an XSD schema file for validation.
        max_file_size_mb: Maximum allowed file size in megabytes.

    Returns:
        A dictionary containing:
            - 'valid': bool indicating if the XML is valid
            - 'errors': list of error messages (empty if valid)
            - 'warnings': list of warning messages
            - 'root_tag': the root element tag name (if parsing succeeded)
            - 'namespaces': dict of namespaces found in the document
            - 'element_count': total number of elements
            - 'tree': the parsed ElementTree object (if parsing succeeded)
    """
    result: Dict[str, Any] = {
        'valid': False,
        'errors': [],
        'warnings': [],
        'root_tag': None,
        'namespaces': {},
        'element_count': 0,
        'tree': None,
    }

    # --- Step 1: Check file existence ---
    if not os.path.exists(file_path):
        result['errors'].append(f"File not found: {file_path}")
        return result

    if not os.path.isfile(file_path):
        result['errors'].append(f"Path is not a file: {file_path}")
        return result

    # --- Step 2: Check file extension ---
    _, ext = os.path.splitext(file_path)
    if ext.lower() not in ('.xml', '.xsl', '.xslt', '.svg', '.xhtml'):
        result['warnings'].append(
            f"File extension '{ext}' is not a typical XML extension."
        )

    # --- Step 3: Check file size ---
    file_size_bytes = os.path.getsize(file_path)
    file_size_mb = file_size_bytes / (1024 * 1024)
    if file_size_mb > max_file_size_mb:
        result['errors'].append(
            f"File size ({file_size_mb:.2f} MB) exceeds maximum allowed size "
            f"({max_file_size_mb:.2f} MB)."
        )
        return result

    if file_size_bytes == 0:
        result['errors'].append("File is empty.")
        return result

    # --- Step 4: Check for basic content validity (no null bytes, etc.) ---
    try:
        with open(file_path, 'rb') as f:
            raw_content = f.read(1024)  # Read first 1KB for checks
            if b'\x00' in raw_content:
                result['errors'].append(
                    "File contains null bytes and may not be a valid XML file."
                )
                return result
    except IOError as e:
        result['errors'].append(f"Could not read file: {e}")
        return result

    # --- Step 5: Well-formedness check using lxml ---
    try:
        parser = etree.XMLParser(
            resolve_entities=False,  # Security: prevent XXE attacks
            no_network=True,         # Security: prevent network access
            dtd_validation=False,
            remove_comments=False,
            remove_blank_text=False,
        )
        tree = etree.parse(file_path, parser)
        root = tree.getroot()
    except etree.XMLSyntaxError as e:
        result['errors'].append(f"XML is not well-formed: {e}")
        return result
    except Exception as e:
        result['errors'].append(f"Error parsing XML: {e}")
        return result

    # --- Step 6: Extract basic information ---
    result['root_tag'] = root.tag
    result['tree'] = tree

    # Extract namespaces
    namespaces = {}
    for event, elem in etree.iterparse(file_path, events=('start-ns',)):
        prefix, uri = elem
        if prefix in namespaces and namespaces[prefix] != uri:
            result['warnings'].append(
                f"Namespace prefix '{prefix}' is mapped to multiple URIs."
            )
        namespaces[prefix] = uri
    result['namespaces'] = namespaces

    # Count elements
    element_count = sum(1 for _ in root.iter())
    result['element_count'] = element_count

    if element_count > 100000:
        result['warnings'].append(
            f"Document contains {element_count} elements, which is very large."
        )

    # --- Step 7: XSD Schema Validation (if schema provided) ---
    if xsd_path:
        if not os.path.exists(xsd_path):
            result['errors'].append(f"XSD schema file not found: {xsd_path}")
            return result

        try:
            xsd_tree = etree.parse(xsd_path)
            xsd_schema = etree.XMLSchema(xsd_tree)

            is_valid = xsd_schema.validate(tree)

            if not is_valid:
                for error in xsd_schema.error_log:
                    result['errors'].append(
                        f"Schema validation error (line {error.line}): {error.message}"
                    )
                return result

        except etree.XMLSchemaParseError as e:
            result['errors'].append(f"Error parsing XSD schema: {e}")
            return result
        except Exception as e:
            result['errors'].append(f"Schema validation error: {e}")
            return result

    # --- Step 8: Additional checks ---
    # Check for potentially dangerous content
    dangerous_patterns = [
        '<!ENTITY',
        '<!DOCTYPE',
        'SYSTEM',
    ]
    try:
        with open(file_path, 'r', encoding='utf-8', errors='replace') as f:
            content = f.read()
            for pattern in dangerous_patterns:
                if pattern in content.upper():
                    result['warnings'].append(
                        f"Document contains '{pattern}' which could indicate "
                        f"a security risk (e.g., XXE attack)."
                    )
    except Exception:
        pass  # Non-critical check

    # Check for mixed content warnings
    _check_mixed_content(root, result['warnings'])

    # If we made it here with no errors, the document is valid
    if not result['errors']:
        result['valid'] = True

    return result


def _check_mixed_content(element: etree._Element, warnings: List[str], max_warnings: int = 5) -> None:
    """Check for elements that have both text content and child elements (mixed content)."""
    warning_count = 0
    for elem in element.iter():
        if warning_count >= max_warnings:
            warnings.append("... (additional mixed content warnings suppressed)")
            break
        if len(elem) > 0 and elem.text and elem.text.strip():
            warnings.append(
                f"Element '{elem.tag}' has mixed content "
                f"(both text and child elements)."
            )
            warning_count += 1


def print_validation_report(result: Dict[str, Any]) -> None:
    """Pretty-prints the validation result."""
    print("=" * 60)
    print("XML VALIDATION REPORT")
    print("=" * 60)

    status = "✅ VALID" if result['valid'] else "❌ INVALID"
    print(f"Status: {status}")
    print(f"Root Tag: {result['root_tag'] or 'N/A'}")
    print(f"Element Count: {result['element_count']}")

    if result['namespaces']:
        print(f"\nNamespaces ({len(result['namespaces'])}):")
        for prefix, uri in result['namespaces'].items():
            prefix_display = prefix if prefix else "(default)"
            print(f"  {prefix_display} -> {uri}")

    if result['errors']:
        print(f"\nErrors ({len(result['errors'])}):")
        for i, error in enumerate(result['errors'], 1):
            print(f"  {i}. {error}")

    if result['warnings']:
        print(f"\nWarnings ({len(result['warnings'])}):")
        for i, warning in enumerate(result['warnings'], 1):
            print(f"  {i}. {warning}")

    print("=" * 60)


def xml_to_dict(element: etree._Element) -> Dict[str, Any]:
    """
    Converts an XML element tree to a Python dictionary.
    Useful for further processing of validated XML.
    """
    result = {}

    # Handle attributes
    if element.attrib:
        result['@attributes'] = dict(element.attrib)

    # Handle text content
    if element.text and element.text.strip():
        if len(element) == 0:
            return element.text.strip()
        result['#text'] = element.text.strip()

    # Handle children
    children: Dict[str, Any] = {}
    for child in element:
        child_tag = child.tag
        child_data = xml_to_dict(child)

        if child_tag in children:
            # Convert to list if multiple children with same tag
            if not isinstance(children[child_tag], list):
                children[child_tag] = [children[child_tag]]
            children[child_tag].append(child_data)
        else:
            children[child_tag] = child_data

    result.update(children)

    return result


